import React from 'react';
import { Button } from '../ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card';

class ErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            hasError: false,
            error: null,
            errorInfo: null
        };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true };
    }

    componentDidCatch(error, errorInfo) {
        this.setState({
            error,
            errorInfo
        });

        console.error('Error Boundary caught an error:', error, errorInfo);

        if (window.location.hostname !== 'localhost') {
            // TODO: Send to error tracking service (Sentry, etc.)
        }
    }

    handleReset = () => {
        this.setState({
            hasError: false,
            error: null,
            errorInfo: null
        });

        if (this.props.onReset) {
            this.props.onReset();
        } else {
            window.location.reload();
        }
    };

    render() {
        if (this.state.hasError) {
            return (
                <div className="min-h-screen flex items-center justify-center p-4 bg-gray-50">
                    <Card className="max-w-2xl w-full">
                        <CardHeader>
                            <CardTitle className="text-red-600">
                                Something went wrong
                            </CardTitle>
                            <CardDescription>
                                An unexpected error occurred. Please try refreshing the page.
                            </CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {process.env.NODE_ENV === 'development' && this.state.error && (
                                <div className="bg-gray-100 p-4 rounded-md overflow-auto">
                                    <p className="font-mono text-sm text-red-600 mb-2">
                                        {this.state.error.toString()}
                                    </p>
                                    {this.state.errorInfo && (
                                        <pre className="text-xs text-gray-700 whitespace-pre-wrap">
                                            {this.state.errorInfo.componentStack}
                                        </pre>
                                    )}
                                </div>
                            )}

                            <div className="flex gap-2">
                                <Button onClick={this.handleReset}>
                                    Try Again
                                </Button>
                                <Button
                                    variant="outline"
                                    onClick={() => window.location.href = '/'}
                                >
                                    Go to Home
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            );
        }

        return this.props.children;
    }
}

export default ErrorBoundary;

import React from 'react';
import { Navigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { hasPermission } from '../../constants/permissions';

/**
 * A wrapper component that conditionally renders its children
 * if the current user has the required permission.
 * 
 * Used for both protecting entire Routes (redirecting if unauthorized)
 * and hiding specific UI elements like buttons or links.
 */
const RequirePermission = ({ permission, children, fallback = null, isRoute = false }) => {
    const { user, loading } = useAuth();

    if (loading) {
        return isRoute ? <div>Loading...</div> : null;
    }

    if (!user) {
        return isRoute ? <Navigate to="/login" replace /> : null;
    }

    // SUPER_ADMIN implicitly can do anything (or handled via hasPermission if mapped)
    // but we can also just rely on hasPermission which checks the exact mapping.
    const allowed = hasPermission(user.role, permission);

    if (!allowed) {
        if (isRoute) {
            return fallback ? fallback : <Navigate to="/unauthorized" replace />;
        }
        return fallback;
    }

    return <>{children}</>;
};

export default RequirePermission;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, ChevronDown, Check } from 'lucide-react';

const CustomDatePicker = ({ value, onChange, label, placeholder = "Select Date" }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [viewDate, setViewDate] = useState(value ? new Date(value) : new Date());
  const [showYearPicker, setShowYearPicker] = useState(false);
  const [openUpward, setOpenUpward] = useState(false);
  const containerRef = useRef(null);

  const months = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"
  ];

  const daysOfWeek = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];

  // Handle click outside and smart positioning
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (containerRef.current && !containerRef.current.contains(e.target)) {
        setIsOpen(false);
        setShowYearPicker(false);
      }
    };

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);

      // Smart positioning logic
      if (containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        const pickerHeight = 350; // Estimated height
        setOpenUpward(spaceBelow < pickerHeight);
      }
    }

    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  const getDaysInMonth = (month, year) => new Date(year, month + 1, 0).getDate();
  const getFirstDayOfMonth = (month, year) => new Date(year, month, 1).getDay();

  const handlePrevMonth = () => {
    setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 1));
  };

  const handleDateSelect = (day) => {
    const selectedDate = new Date(viewDate.getFullYear(), viewDate.getMonth(), day);
    onChange(selectedDate.toISOString().split('T')[0]);
    setIsOpen(false);
  };

  const years = [];
  const currentYear = new Date().getFullYear();
  for (let i = currentYear - 100; i <= currentYear + 10; i++) {
    years.push(i);
  }

  const renderCalendar = () => {
    const daysInMonth = getDaysInMonth(viewDate.getMonth(), viewDate.getFullYear());
    const firstDay = getFirstDayOfMonth(viewDate.getMonth(), viewDate.getFullYear());
    const days = [];

    // Empty slots for previous month
    for (let i = 0; i < firstDay; i++) {
      days.push(<div key={`empty-${i}`} className="h-8 w-8"></div>);
    }

    // Actual days
    for (let i = 1; i <= daysInMonth; i++) {
      const isSelected = value && new Date(value).getDate() === i && 
                         new Date(value).getMonth() === viewDate.getMonth() && 
                         new Date(value).getFullYear() === viewDate.getFullYear();
      const isToday = new Date().getDate() === i && 
                      new Date().getMonth() === viewDate.getMonth() && 
                      new Date().getFullYear() === viewDate.getFullYear();

      days.push(
        <button
          key={i}
          type="button"
          onClick={() => handleDateSelect(i)}
          className={`h-8 w-8 flex items-center justify-center rounded-xl text-xs font-bold transition-all ${
            isSelected 
              ? 'bg-primary text-primary-foreground shadow-lg shadow-primary/20 scale-110' 
              : isToday 
                ? 'border border-primary text-primary hover:bg-primary/10' 
                : 'text-muted-foreground hover:bg-accent hover:text-foreground'
          }`}
        >
          {i}
        </button>
      );
    }

    return days;
  };

  return (
    <div className="relative w-full" ref={containerRef}>
      {label && <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1 mb-1.5 block">{label}</label>}
      <div className="relative">
        <button
          type="button"
          onClick={() => setIsOpen(!isOpen)}
          className={`w-full h-9 bg-muted/30 border border-border rounded-lg px-3 text-xs flex items-center justify-between transition-all hover:bg-muted/50 active:scale-[0.98] ${isOpen ? 'ring-1 ring-primary/20 border-primary' : ''}`}
        >
          <span className={value ? 'text-foreground font-bold' : 'text-muted-foreground'}>
            {value ? new Date(value).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }) : placeholder}
          </span>
          <CalendarIcon className={`w-3.5 h-3.5 text-muted-foreground transition-colors ${isOpen ? 'text-primary' : ''}`} />
        </button>

        {isOpen && (
          <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-[2px]" onClick={() => setIsOpen(false)}></div>
            <div className="relative w-64 bg-card border border-border rounded-2xl shadow-[0_20px_70px_rgba(0,0,0,0.5)] p-5 animate-in zoom-in-95 slide-in-from-bottom-4 duration-300 ease-[cubic-bezier(0.32,0.72,0,1)]">
              {/* Calendar Header */}
              <div className="flex items-center justify-between mb-5">
                <button 
                  type="button"
                  onClick={() => setShowYearPicker(!showYearPicker)}
                  className="flex items-center gap-2 px-2 py-1.5 rounded-lg hover:bg-accent transition-all group"
                >
                  <span className="text-sm font-black text-foreground tracking-tight">
                    {months[viewDate.getMonth()]} {viewDate.getFullYear()}
                  </span>
                  <ChevronDown className={`w-3.5 h-3.5 text-muted-foreground transition-transform duration-300 ${showYearPicker ? 'rotate-180' : ''}`} />
                </button>
                <div className="flex items-center gap-1.5">
                  <button type="button" onClick={handlePrevMonth} className="p-1.5 hover:bg-accent rounded-lg text-muted-foreground transition-all"><ChevronLeft className="w-5 h-5" /></button>
                  <button type="button" onClick={handleNextMonth} className="p-1.5 hover:bg-accent rounded-lg text-muted-foreground transition-all"><ChevronRight className="w-5 h-5" /></button>
                </div>
              </div>

              {showYearPicker ? (
                <div className="grid grid-cols-3 gap-2 h-56 overflow-y-auto hide-scrollbar px-1">
                  {years.reverse().map(year => (
                    <button
                      key={year}
                      type="button"
                      onClick={() => {
                        setViewDate(new Date(year, viewDate.getMonth(), 1));
                        setShowYearPicker(false);
                      }}
                      className={`py-2.5 rounded-xl text-xs font-bold transition-all ${
                        viewDate.getFullYear() === year 
                          ? 'bg-primary text-primary-foreground' 
                          : 'text-muted-foreground hover:bg-accent hover:text-foreground'
                      }`}
                    >
                      {year}
                    </button>
                  ))}
                </div>
              ) : (
                <>
                  {/* Days of Week */}
                  <div className="grid grid-cols-7 mb-3">
                    {daysOfWeek.map(day => (
                      <div key={day} className="text-center text-[10px] font-black text-muted-foreground/40 uppercase tracking-widest">
                        {day}
                      </div>
                    ))}
                  </div>

                  {/* Days Grid */}
                  <div className="grid grid-cols-7 gap-1.5">
                    {renderCalendar()}
                  </div>

                  {/* Actions */}
                  <div className="flex items-center justify-between mt-6 pt-5 border-t border-border/50">
                    <button 
                      type="button"
                      onClick={() => { onChange(''); setIsOpen(false); }}
                      className="text-[11px] font-black text-muted-foreground hover:text-destructive transition-colors uppercase tracking-widest"
                    >
                      Clear
                    </button>
                    <button 
                      type="button"
                      onClick={() => {
                        const today = new Date();
                        onChange(today.toISOString().split('T')[0]);
                        setViewDate(today);
                        setIsOpen(false);
                      }}
                      className="text-[11px] font-black text-primary hover:opacity-80 transition-opacity uppercase tracking-widest"
                    >
                      Today
                    </button>
                  </div>
                </>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CustomDatePicker;

import React, { useEffect } from 'react';
import { Plus, X } from 'lucide-react';
import { cn } from '@/lib/utils';

export default function CustomModal({ isOpen, onClose, title, children, maxWidth = 'max-w-md' }) {
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        onClose();
      }
    };
    if (isOpen) {
      window.addEventListener('keydown', handleKeyDown);
    }
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <>
      {/* Backdrop sits below navbar (z-20 vs nav z-30) */}
      <div className="fixed inset-0 bg-black/50 z-[20]" onClick={onClose} />

      {/* Modal dialog sits below navbar (z-25) and is pushed down 96px (top-24) to avoid collision */}
      <div className={cn("fixed top-24 left-1/2 -translate-x-1/2 z-[25] bg-card border border-border rounded-xl shadow-xl w-full text-left flex flex-col max-h-[calc(100vh-8rem)]", maxWidth)}>
        <div className="px-4 py-3 border-b border-border flex items-center justify-between shrink-0 bg-card z-10 rounded-t-xl">
          <h3 className="text-[11px] font-bold text-foreground uppercase tracking-widest">
            {title}
          </h3>
          <button type="button" onClick={onClose} className="p-1 hover:bg-muted rounded transition-colors" title="Close">
            <Plus className="w-4 h-4 rotate-45" />
          </button>
        </div>
        <div className="overflow-y-auto flex-1">
          {children}
        </div>
      </div>
    </>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { ChevronDown, Check } from 'lucide-react';

const CustomSelect = ({ value, onChange, options, placeholder, className = "" }) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef(null);

  const selectedOption = options.find(opt => opt.id === value);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (containerRef.current && !containerRef.current.contains(e.target)) {
        setIsOpen(false);
      }
    };
    if (isOpen) document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  return (
    <div className={`relative w-full ${className}`} ref={containerRef}>
      <button 
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full h-9 bg-muted/30 border border-border rounded-lg px-3 text-xs flex items-center justify-between transition-all duration-300 hover:bg-muted/50 active:scale-[0.98] ${isOpen ? 'ring-1 ring-primary/20 border-primary shadow-inner' : ''}`}
      >
        <span className={`transition-all duration-300 ${selectedOption ? 'text-foreground font-bold translate-x-0' : 'text-muted-foreground translate-x-0'}`}>
          {selectedOption ? selectedOption.label : placeholder}
        </span>
        <ChevronDown className={`w-3 h-3 text-muted-foreground transition-transform duration-500 ease-[cubic-bezier(0.32,0.72,0,1)] ${isOpen ? 'rotate-180 text-primary' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute top-full left-0 right-0 mt-1.5 bg-card border border-border rounded-xl shadow-[0_20px_50px_rgba(0,0,0,0.3)] z-[1000] py-1.5 animate-in fade-in zoom-in-95 slide-in-from-top-2 duration-300 ease-[cubic-bezier(0.32,0.72,0,1)] dark:bg-gray-900 dark:border-gray-800">
          <div className="max-h-60 overflow-y-auto hide-scrollbar px-1.5 space-y-0.5">
            {options.length > 0 ? options.map((opt) => (
              <button
                key={opt.id}
                type="button"
                onClick={() => {
                  onChange(opt.id);
                  setIsOpen(false);
                }}
                className={`w-full flex items-center justify-between px-2.5 py-1.5 rounded-lg text-xs transition-all duration-200 group ${value === opt.id ? 'bg-primary/10 text-primary font-bold dark:bg-primary/20 dark:text-primary' : 'text-muted-foreground hover:bg-accent hover:text-foreground dark:text-gray-300 dark:hover:bg-gray-800 dark:hover:text-white'}`}
              >
                <span className="transition-transform duration-200 group-hover:translate-x-0.5">{opt.label}</span>
                {value === opt.id && (
                  <Check className="w-3.5 h-3.5 text-primary animate-in zoom-in-50 duration-300" />
                )}
              </button>
            )) : (
              <div className="px-3 py-2 text-[10px] text-muted-foreground italic text-center dark:text-gray-500">No options available</div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default CustomSelect;

