                      <div className="text-[10px] text-foreground space-y-0.5">
                        <h4 className="font-extrabold">{student.firstName} {student.lastName || ''}</h4>
                        <p className="text-muted-foreground">Class: {student.Class?.name} - {student.Section?.name}</p>
