export default StudentIDCard;

import React, { useState, useEffect } from 'react';
import { FileText, Printer } from 'lucide-react';
import api from '../../lib/api';
import { toast } from 'sonner';
import { DatePicker } from '../../components/ui/date-picker';

const TransferCertificate = () => {
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(false);
  const [generating, setGenerating] = useState(false);
  const [formData, setFormData] = useState({
    studentId: '',
    leavingDate: '',
    reason: '',
    remarks: ''
  });
  const [preview, setPreview] = useState(null);

  useEffect(() => {
    const fetchStudents = async () => {
      try {
        setLoading(true);
        const response = await api.get('/students?isDisabled=false');
        setStudents(response.data.data || []);
      } catch (error) {
        toast.error('Failed to fetch students');
      } finally {
        setLoading(false);
      }
    };
    fetchStudents();
  }, []);

  const handleGenerate = async (e) => {
    e.preventDefault();
    if (!formData.studentId || !formData.leavingDate) {
      return toast.error('Student and leaving date are required');
    }

    try {
      setGenerating(true);
      const response = await api.post('/certificates/transfer-certificate', formData);
      setPreview(response.data.data);
      toast.success('Transfer certificate generated successfully');
    } catch (error) {
      toast.error('Failed to generate transfer certificate');
    } finally {
      setGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!preview) return;
    const printContent = `
      <html>
        <head>
          <title>Transfer Certificate - ${preview.student?.firstName || 'Student'}</title>
          <style>
            body {
              font-family: system-ui, -apple-system, sans-serif;
              margin: 0;
              padding: 40px;
              display: flex;
              align-items: center;
              justify-content: center;
              min-height: 100vh;
              background-color: #fff;
              color: #000;
            }
            .tc-container {
              border: 6px double #374151;
              padding: 40px;
              max-width: 700px;
              width: 100%;
              box-sizing: border-box;
            }
            h1 {
              text-align: center;
              font-size: 24px;
              font-weight: 900;
              letter-spacing: 1px;
              margin-bottom: 30px;
              text-transform: uppercase;
            }
            .field-row {
              margin: 15px 0;
              font-size: 14px;
              line-height: 1.6;
              border-bottom: 1px dashed #ccc;
              padding-bottom: 4px;
            }
            .field-row strong {
              display: inline-block;
              width: 180px;
              color: #374151;
            }
            .footer-row {
              margin-top: 50px;
              display: flex;
              justify-content: space-between;
              font-size: 12px;
              color: #4b5563;
            }
          </style>
        </head>
        <body>
          <div class="tc-container">
            <h1>Transfer Certificate</h1>

            <div class="field-row"><strong>Student Name:</strong> ${preview.student?.firstName} ${preview.student?.lastName || ''}</div>
            <div class="field-row"><strong>Admission Number:</strong> ${preview.student?.admissionNo}</div>
            <div class="field-row"><strong>Class & Section:</strong> ${preview.student?.Class?.name || 'N/A'} - ${preview.student?.Section?.name || 'N/A'}</div>
            <div class="field-row"><strong>Date of Birth:</strong> ${new Date(preview.student?.dob).toLocaleDateString()}</div>
            <div class="field-row"><strong>Leaving Date:</strong> ${new Date(preview.leavingDate).toLocaleDateString()}</div>
            <div class="field-row"><strong>Reason for Leaving:</strong> ${preview.reason || 'Family request'}</div>
            <div class="field-row"><strong>Remarks:</strong> ${preview.remarks || 'N/A'}</div>

            <div class="footer-row">
              <div>Issue Date: ${new Date(preview.issueDate).toLocaleDateString()}</div>
              <div>Principal Signature: _____________________</div>
            </div>
          </div>
          <script>
            window.onload = function() {
              window.print();
              setTimeout(() => { window.close(); }, 500);
            };
          </script>
        </body>
      </html>
    `;

    const printWindow = window.open('', '_blank');
    printWindow.document.write(printContent);
    printWindow.document.close();
  };

  const selectedStudent = students.find(s => s.id === formData.studentId);

  return (
    <div className="p-4 space-y-4 animate-in fade-in duration-500 max-w-[1400px] mx-auto">
      <div className="border-b border-border pb-3">
        <h1 className="text-lg font-black text-foreground tracking-tight">Transfer Certificate</h1>
        <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold opacity-70">Generate student transfer certificates</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-card border border-border rounded-xl p-4">
          <h3 className="text-[11px] font-bold text-foreground uppercase tracking-widest mb-4">TC Details</h3>
          <form onSubmit={handleGenerate} className="space-y-4">
            <div className="space-y-1">
              <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Select Student *</label>
              <select
                value={formData.studentId}
                onChange={(e) => setFormData({...formData, studentId: e.target.value})}
                className="w-full h-9 bg-muted/30 border border-border rounded-lg px-3 text-xs focus:outline-none focus:ring-1 focus:ring-primary/20"
                required
              >
                <option value="">Choose Student</option>
                {students.map(s => (
                  <option key={s.id} value={s.id}>
