import React, { useState, useEffect } from 'react';
import { Download, Database, Trash2, Calendar, FileArchive } from 'lucide-react';
import api from '../../lib/api';
import { toast } from 'sonner';

const BackupSetting = () => {
  const [backups, setBackups] = useState([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);

  const fetchBackups = async () => {
    try {
      setLoading(true);
      const response = await api.get('/settings/backups');
      setBackups(response.data.data || []);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to fetch backups');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBackups();
  }, []);

  const handleCreateBackup = async () => {
    if (!window.confirm('Are you sure you want to create a database backup?')) return;

    try {
      setCreating(true);
      const response = await api.post('/settings/backups/create');
      toast.success('Backup created successfully');
      fetchBackups();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create backup');
    } finally {
      setCreating(false);
    }
  };

  const handleDownloadBackup = async (id, filename) => {
    try {
      const response = await api.get(`/settings/backups/${id}/download`, {
        responseType: 'blob'
      });

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', filename);
      document.body.appendChild(link);
      link.click();
      link.remove();

      toast.success('Backup downloaded successfully');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to download backup');
    }
  };

  const handleDeleteBackup = async (id) => {
    if (!window.confirm('Are you sure you want to delete this backup?')) return;

    try {
      await api.delete(`/settings/backups/${id}`);
      toast.success('Backup deleted successfully');
      fetchBackups();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to delete backup');
    }
  };

  const formatFileSize = (bytes) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return Math.round(bytes / Math.pow(k, i) * 100) / 100 + ' ' + sizes[i];
  };

  return (
    <div className="p-4 space-y-4 animate-in fade-in duration-500 max-w-[1400px] mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-1 border-b border-border pb-3">
        <div>
          <h1 className="text-lg font-black text-foreground tracking-tight">Backup & Restore</h1>
          <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold opacity-70">
            Manage database backups
          </p>
        </div>
        <button
          onClick={handleCreateBackup}
          disabled={creating}
          className="h-8 px-4 bg-primary text-primary-foreground rounded-lg text-[10px] font-bold hover:opacity-90 transition-all flex items-center gap-2 w-fit disabled:opacity-50"
        >
          <Database className="w-3 h-3" />
          {creating ? 'Creating...' : 'Create Backup'}
        </button>
      </div>

      {/* Warning Notice */}
      <div className="bg-yellow-500/10 border border-yellow-500/20 rounded-xl p-4">
        <div className="flex items-start gap-3">
          <FileArchive className="w-5 h-5 text-yellow-600 flex-shrink-0 mt-0.5" />
          <div>
            <h3 className="text-xs font-bold text-yellow-600 mb-1">Important Information</h3>
            <ul className="text-[10px] text-yellow-600/90 space-y-1">
              <li>Backups include database records exported as JSON</li>
              <li>Download and store backups externally</li>
              <li>Automatic restore is disabled to protect production data</li>
              <li>Use a verified manual restore process for production incidents</li>
            </ul>
          </div>
        </div>
      </div>

      {/* Backups List */}
      <div className="bg-card border border-border rounded-xl overflow-hidden">
        <div className="px-3 py-2 border-b border-border bg-muted/10 flex items-center gap-2">
          <Database className="w-4 h-4 text-primary" />
          <h3 className="text-[10px] font-bold text-foreground uppercase tracking-widest">Available Backups</h3>
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-12">
            <div className="flex flex-col items-center gap-2">
              <div className="w-8 h-8 border-3 border-primary/20 border-t-primary rounded-full animate-spin"></div>
              <span className="text-[10px] font-bold text-primary uppercase tracking-widest">Loading...</span>
            </div>
          </div>
        ) : backups.length === 0 ? (
          <div className="p-12 text-center">
            <Database className="w-8 h-8 text-muted-foreground mx-auto mb-2 opacity-50" />
            <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">No backups found</p>
            <p className="text-[10px] text-muted-foreground mt-1">Create your first backup to get started</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-muted/5 border-b border-border">
                <tr>
                  <th className="px-4 py-3 text-left text-[10px] font-bold text-muted-foreground uppercase tracking-widest">
                    Filename
                  </th>
                  <th className="px-4 py-3 text-left text-[10px] font-bold text-muted-foreground uppercase tracking-widest">
                    Created Date
                  </th>
                  <th className="px-4 py-3 text-left text-[10px] font-bold text-muted-foreground uppercase tracking-widest">
                    File Size
                  </th>
                  <th className="px-4 py-3 text-center text-[10px] font-bold text-muted-foreground uppercase tracking-widest">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {backups.map((backup) => (
                  <tr key={backup.id} className="hover:bg-muted/5 transition-colors">
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2">
                        <FileArchive className="w-4 h-4 text-primary" />
                        <span className="text-xs font-bold text-foreground">{backup.filename}</span>
                      </div>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2">
                        <Calendar className="w-3 h-3 text-muted-foreground" />
                        <span className="text-xs text-muted-foreground">
                          {new Date(backup.createdAt).toLocaleString()}
                        </span>
                      </div>
                    </td>
                    <td className="px-4 py-3">
                      <span className="text-xs text-muted-foreground">
                        {formatFileSize(backup.fileSize || 0)}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center justify-center gap-2">
                        <button
                          onClick={() => handleDownloadBackup(backup.id, backup.filename)}
                          className="p-1.5 hover:bg-muted rounded-lg transition-colors"
                          title="Download"
                        >
                          <Download className="w-3.5 h-3.5 text-muted-foreground" />
                        </button>
                        <button
                          onClick={() => handleDeleteBackup(backup.id)}
                          className="p-1.5 hover:bg-destructive/10 rounded-lg transition-colors"
                          title="Delete"
                        >
                          <Trash2 className="w-3.5 h-3.5 text-destructive" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Backup Schedule Info */}
      <div className="bg-card border border-border rounded-xl overflow-hidden">
        <div className="px-4 py-3 border-b border-border bg-muted/10">
          <h3 className="text-[10px] font-bold text-foreground uppercase tracking-widest">Automatic Backup Schedule</h3>
        </div>
        <div className="p-4">
          <p className="text-xs text-muted-foreground mb-3">
            Configure automatic backup schedule to ensure data safety.
          </p>
          <div className="flex items-center gap-2 p-3 bg-muted/20 rounded-lg">
            <input
              type="checkbox"
              id="autoBackup"
              className="w-4 h-4 rounded border-border"
              disabled
            />
            <label htmlFor="autoBackup" className="text-xs font-medium text-foreground flex-1">
              Enable Daily Automatic Backups (coming soon)
            </label>
          </div>
          <p className="text-[10px] text-muted-foreground mt-2 ml-6">
            Automatic scheduling needs a background worker or database provider backup schedule.
          </p>
        </div>
      </div>
    </div>
  );
};

export default BackupSetting;

import React, { useState } from 'react';
import { Bell, Send, Users } from 'lucide-react';
import api from '../../lib/api';
import { toast } from 'sonner';
import { getErrorMessage } from '../../lib/errorHandler';

const ROLES = [
  { value: '', label: 'All Users' },
  { value: 'ADMIN', label: 'Admins' },
  { value: 'TEACHER', label: 'Teachers' },
  { value: 'ACCOUNTANT', label: 'Accountants' },
  { value: 'RECEPTIONIST', label: 'Receptionists' },
];

const NOTIFICATION_TYPES = [
  { value: 'info', label: 'Info' },
  { value: 'success', label: 'Success' },
  { value: 'warning', label: 'Warning' },
  { value: 'error', label: 'Error' },
];

const BroadcastNotification = () => {
  const [form, setForm] = useState({ title: '', message: '', type: 'info', targetRole: '' });
  const [sending, setSending] = useState(false);
  const [lastResult, setLastResult] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.title.trim()) return toast.error('Title is required');
    if (!form.message.trim()) return toast.error('Message is required');

    try {
      setSending(true);
      const res = await api.post('/notifications/broadcast', form);
      const data = res.data.data;
      setLastResult(data);
      toast.success(`Notification sent to ${data.sent} user(s)`);
      setForm({ title: '', message: '', type: 'info', targetRole: '' });
    } catch (err) {
      toast.error(getErrorMessage(err, 'Failed to send notification'));
    } finally {
      setSending(false);
    }
  };

  const typeColors = {
    info: 'border-blue-500/30 bg-blue-500/5',
    success: 'border-green-500/30 bg-green-500/5',
    warning: 'border-yellow-500/30 bg-yellow-500/5',
    error: 'border-red-500/30 bg-red-500/5',
  };

  return (
    <div className="p-4 space-y-4 animate-in fade-in duration-500 max-w-[900px] mx-auto">
      <div className="border-b border-border pb-3">
        <h1 className="text-lg font-black text-foreground tracking-tight">Broadcast Notification</h1>
        <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold opacity-70">Send announcements to all users or specific roles</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Form */}
        <div className="lg:col-span-2 bg-card border border-border rounded-xl p-5">
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-1">
              <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Notification Title *</label>
              <input
                type="text"
                placeholder="e.g. School closed tomorrow"
                value={form.title}
                onChange={e => setForm({ ...form, title: e.target.value })}
                className="w-full h-9 bg-muted/30 border border-border rounded-lg px-3 text-xs focus:outline-none focus:ring-1 focus:ring-primary/20"
                required
              />
            </div>

            <div className="space-y-1">
              <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Message *</label>
              <textarea
                placeholder="Write the notification message here..."
                value={form.message}
                onChange={e => setForm({ ...form, message: e.target.value })}
                rows={5}
                className="w-full bg-muted/30 border border-border rounded-lg px-3 py-2 text-xs focus:outline-none focus:ring-1 focus:ring-primary/20 resize-none"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Type</label>
                <select
                  value={form.type}
                  onChange={e => setForm({ ...form, type: e.target.value })}
                  className="w-full h-9 bg-muted/30 border border-border rounded-lg px-3 text-xs focus:outline-none focus:ring-1 focus:ring-primary/20"
                >
                  {NOTIFICATION_TYPES.map(t => <option key={t.value} value={t.value}>{t.label}</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Target Audience</label>
                <select
                  value={form.targetRole}
                  onChange={e => setForm({ ...form, targetRole: e.target.value })}
                  className="w-full h-9 bg-muted/30 border border-border rounded-lg px-3 text-xs focus:outline-none focus:ring-1 focus:ring-primary/20"
                >
                  {ROLES.map(r => <option key={r.value} value={r.value}>{r.label}</option>)}
                </select>
              </div>
            </div>

            {/* Preview */}
            {(form.title || form.message) && (
              <div className={`border rounded-xl p-3 transition-all ${typeColors[form.type] || typeColors.info}`}>
                <p className="text-[9px] font-bold uppercase tracking-widest text-muted-foreground mb-1">Preview</p>
                <p className="text-xs font-bold text-foreground">{form.title || '—'}</p>
                <p className="text-xs text-muted-foreground mt-0.5">{form.message || '—'}</p>
              </div>
            )}

            <button
              type="submit"
              disabled={sending}
              className="w-full h-10 bg-primary text-primary-foreground rounded-lg text-[11px] font-bold hover:opacity-90 disabled:opacity-50 flex items-center justify-center gap-2 transition-all"
            >
              {sending ? (
                <><div className="animate-spin w-4 h-4 border-b-2 border-white rounded-full" /> Sending...</>
              ) : (
                <><Send className="w-4 h-4" /> Send Notification</>
              )}
            </button>
          </form>
        </div>

        {/* Info panel */}
        <div className="space-y-4">
          <div className="bg-card border border-border rounded-xl p-4">
            <div className="flex items-center gap-2 mb-3">
              <Bell className="w-4 h-4 text-primary" />
              <h3 className="text-xs font-bold text-foreground">How it works</h3>
            </div>
            <div className="space-y-2 text-[11px] text-muted-foreground">
              <p>• Notifications appear in the notification bell for all targeted users.</p>
              <p>• Selecting a specific role targets only those users.</p>
              <p>• "All Users" sends to every active account in the system.</p>
              <p>• Users can mark notifications as read or delete them.</p>
            </div>
          </div>

          <div className="bg-card border border-border rounded-xl p-4">
            <div className="flex items-center gap-2 mb-3">
              <Users className="w-4 h-4 text-primary" />
              <h3 className="text-xs font-bold text-foreground">Target Roles</h3>
            </div>
            <div className="space-y-1.5">
              {ROLES.filter(r => r.value).map(r => (
                <div key={r.value} className="flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-primary" />
                  <span className="text-[11px] text-muted-foreground">{r.label}</span>
                </div>
              ))}
            </div>
          </div>

          {lastResult && (
            <div className="bg-green-500/10 border border-green-500/20 rounded-xl p-4">
              <p className="text-[9px] font-bold uppercase tracking-widest text-green-600 mb-1">Last Sent</p>
              <p className="text-xl font-black text-green-600">{lastResult.sent}</p>
              <p className="text-[11px] text-muted-foreground">users notified • {lastResult.targetRole || 'all roles'}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BroadcastNotification;

