import React, { useState, useEffect } from 'react';
import { Search, Filter, Plus, Edit2, Trash2, Users, ChevronLeft, ChevronRight, Eye } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../../lib/api';
import { toast } from 'sonner';

const StaffList = () => {
  const navigate = useNavigate();
  const [staff, setStaff] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [filters, setFilters] = useState({
    role: '',
    departmentId: '',
    designationId: '',
    gender: ''
  });
  const [pagination, setPagination] = useState({
    page: 1,
    limit: 10,
    total: 0
  });

  const [departments, setDepartments] = useState([]);
  const [designations, setDesignations] = useState([]);
  const [showFilters, setShowFilters] = useState(false);

  // Fetch dropdown data
  useEffect(() => {
    const fetchSetupData = async () => {
      try {
        const [deptRes, desigRes] = await Promise.all([
          api.get('/hr/departments'),
          api.get('/hr/designations')
        ]);
        setDepartments(deptRes.data.data || []);
        setDesignations(desigRes.data.data || []);
      } catch (error) {
        console.error('Failed to load setup data');
      }
    };
    fetchSetupData();
  }, []);

  // Fetch staff
  const fetchStaff = async () => {
    try {
      setLoading(true);
      const params = {
        page: pagination.page,
        limit: pagination.limit,
        search: searchQuery,
        ...filters
      };

      const response = await api.get('/staff', { params });
      setStaff(response.data.data || []);
      setPagination(prev => ({
        ...prev,
        total: response.data.pagination?.total || 0
      }));
    } catch (error) {
      toast.error('Failed to fetch staff');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      fetchStaff();
    }, 300);
    return () => clearTimeout(timer);
  }, [searchQuery, filters, pagination.page, pagination.limit]);

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this staff member?')) return;

    try {
      await api.delete(`/staff/${id}`);
      toast.success('Staff deleted successfully');
      fetchStaff();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to delete staff');
    }
  };

  const clearFilters = () => {
    setFilters({
      role: '',
      departmentId: '',
      designationId: '',
      gender: ''
    });
