import React, { useState, useEffect } from 'react';
import { Plus, Search, Edit2, Trash2, Home, Users, ChevronLeft, ChevronRight } from 'lucide-react';
import api from '../../lib/api';
import { toast } from 'sonner';

const House = () => {
  const [houses, setHouses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingHouse, setEditingHouse] = useState(null);

  const [formData, setFormData] = useState({
    name: '',
    description: ''
  });

  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const fetchHouses = async () => {
    try {
      setLoading(true);
      const response = await api.get('/student-setup/houses');
      setHouses(response.data.data || []);
    } catch (error) {
      toast.error('Failed to fetch houses');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHouses();
  }, []);

  const handleEdit = (house) => {
    setEditingHouse(house);
    setFormData({
      name: house.name,
      description: house.description || ''
    });
  };

  const cancelEdit = () => {
    setEditingHouse(null);
    setFormData({ name: '', description: '' });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.name.trim()) return toast.error('House name is required');

    try {
      setSubmitting(true);
      if (editingHouse) {
        await api.put(`/student-setup/houses/${editingHouse.id}`, formData);
        toast.success('House updated successfully');
      } else {
        await api.post('/student-setup/houses', formData);
        toast.success('House added successfully');
      }
      cancelEdit();
      setCurrentPage(1);
      fetchHouses();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save house');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this house? This may affect student records.')) return;
    try {
      await api.delete(`/student-setup/houses/${id}`);
      toast.success('House deleted');
      fetchHouses();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to delete house');
    }
  };

  const filteredHouses = houses.filter(h =>
    h.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const totalPages = Math.ceil(filteredHouses.length / itemsPerPage);
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredHouses.slice(indexOfFirstItem, indexOfLastItem);

  return (
    <div className="p-4 space-y-4 animate-in fade-in duration-500 max-w-[1200px] mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-1 border-b border-border pb-3">
        <div>
          <h1 className="text-lg font-black text-foreground tracking-tight">Student Houses</h1>
          <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold opacity-70">Manage student houses (Red, Blue, Green, Yellow)</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4">
        <div className="lg:col-span-4">
          <div className="bg-card border border-border rounded-xl shadow-sm overflow-hidden sticky top-4">
            <div className="px-3 py-2 border-b border-border bg-muted/10 flex items-center justify-between">
              <h3 className="text-[10px] font-bold text-foreground uppercase tracking-widest">
                {editingHouse ? 'Update House' : 'Add House'}
              </h3>
              {editingHouse && (
                <button
                  onClick={cancelEdit}
                  className="text-[9px] font-bold text-primary hover:underline uppercase tracking-tight"
                >
                  Cancel
                </button>
              )}
            </div>
            <form onSubmit={handleSubmit} className="p-4 space-y-3">
              <div className="space-y-1">
                <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest ml-1">House Name *</label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  placeholder="e.g. Red House, Blue House"
                  className="w-full h-8 bg-muted/30 border border-border rounded-lg px-2.5 text-[11px] focus:outline-none focus:ring-1 focus:ring-primary/20 transition-all"
                  required
                />
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Description (Optional)</label>
                <textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  placeholder="Brief description..."
                  rows="3"
                  className="w-full bg-muted/30 border border-border rounded-lg px-2.5 py-2 text-[11px] focus:outline-none focus:ring-1 focus:ring-primary/20 transition-all resize-none"
                />
              </div>

              <button
                type="submit"
                disabled={submitting}
                className="w-full h-8 bg-primary text-primary-foreground rounded-lg text-[10px] font-bold shadow-lg shadow-primary/10 hover:opacity-90 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
              >
                {submitting ? (
                  <div className="w-3.5 h-3.5 border-2 border-primary-foreground/30 border-t-primary-foreground rounded-full animate-spin"></div>
                ) : (
                  <>
                    {editingHouse ? <Edit2 className="w-3 h-3" /> : <Plus className="w-3 h-3" />}
                    {editingHouse ? 'Update' : 'Save House'}
                  </>
                )}
              </button>
            </form>
          </div>
        </div>

        <div className="lg:col-span-8">
          <div className="bg-card border border-border rounded-xl shadow-sm overflow-hidden relative">
            {loading && (
              <div className="absolute inset-0 bg-background/50 backdrop-blur-[1px] z-10 flex items-center justify-center">
                <div className="flex flex-col items-center gap-2">
                  <div className="w-8 h-8 border-3 border-primary/20 border-t-primary rounded-full animate-spin"></div>
                  <span className="text-[10px] font-bold text-primary uppercase tracking-widest animate-pulse">Loading...</span>
                </div>
              </div>
            )}

            <div className="px-3 py-2 border-b border-border bg-muted/10 flex items-center justify-between">
              <h3 className="text-[10px] font-bold text-foreground uppercase tracking-widest">House List</h3>
              <div className="relative w-40">
                <Search className="absolute left-2 top-1/2 -translate-y-1/2 w-3 h-3 text-muted-foreground" />
                <input
                  type="text"
                  placeholder="Search..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full h-7 pl-7 pr-2 bg-background border border-border rounded-lg text-[10px] focus:outline-none focus:ring-1 focus:ring-primary/20 transition-all"
                />
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-muted/5 border-b border-border">
                    <th className="px-4 py-2 text-[9px] font-black text-muted-foreground uppercase tracking-widest">House</th>
                    <th className="px-4 py-2 text-[9px] font-black text-muted-foreground uppercase tracking-widest">Description</th>
                    <th className="px-4 py-2 text-[9px] font-black text-muted-foreground uppercase tracking-widest">Students</th>
                    <th className="px-4 py-2 text-[9px] font-black text-muted-foreground uppercase tracking-widest text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border/50">
                  {!loading && currentItems.length > 0 ? currentItems.map((house) => (
                    <tr key={house.id} className="hover:bg-muted/5 transition-colors group">
                      <td className="px-4 py-2.5">
                        <div className="flex items-center gap-2">
                          <Home className="w-3.5 h-3.5 text-primary" />
                          <span className="text-[11px] font-bold text-foreground">{house.name}</span>
                        </div>
                      </td>
                      <td className="px-4 py-2.5">
                        <span className="text-[10px] text-muted-foreground">
                          {house.description || '-'}
                        </span>
                      </td>
                      <td className="px-4 py-2.5">
                        <div className="flex items-center gap-1.5">
                          <Users className="w-3 h-3 text-muted-foreground" />
                          <span className="text-[10px] font-bold text-muted-foreground">
                            {house._count?.students || 0}
                          </span>
                        </div>
                      </td>
                      <td className="px-4 py-2.5">
                        <div className="flex items-center justify-end gap-1.5">
                          <button
                            onClick={() => handleEdit(house)}
                            className="p-1.5 hover:bg-primary/10 hover:text-primary text-muted-foreground rounded-md transition-all"
                          >
                            <Edit2 className="w-3 h-3" />
                          </button>
                          <button
                            onClick={() => handleDelete(house.id)}
                            disabled={house._count?.students > 0}
                            className="p-1.5 hover:bg-destructive/10 hover:text-destructive text-muted-foreground rounded-md transition-all disabled:opacity-30 disabled:cursor-not-allowed"
                          >
                            <Trash2 className="w-3 h-3" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  )) : !loading && (
                    <tr>
                      <td colSpan="4" className="px-4 py-12 text-center">
                        <div className="flex flex-col items-center gap-2 opacity-50">
                          <Home className="w-6 h-6 text-muted-foreground" />
                          <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">No houses found</p>
                        </div>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            {!loading && filteredHouses.length > 0 && (
              <div className="px-3 py-2 bg-muted/5 border-t border-border flex items-center justify-between">
                <p className="text-[9px] font-bold text-muted-foreground uppercase tracking-tighter">
                  Showing {indexOfFirstItem + 1} to {Math.min(indexOfLastItem, filteredHouses.length)} of {filteredHouses.length}
                </p>

                {totalPages > 1 && (
                  <div className="flex items-center gap-1">
                    <button
                      onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                      disabled={currentPage === 1}
                      className="p-1 rounded bg-background border border-border disabled:opacity-30 hover:bg-muted transition-all"
                    >
                      <ChevronLeft className="w-3 h-3" />
                    </button>

                    <div className="flex items-center gap-1 mx-1">
                      {[...Array(totalPages)].map((_, i) => (
                        <button
                          key={i + 1}
                          onClick={() => setCurrentPage(i + 1)}
                          className={`w-5 h-5 flex items-center justify-center rounded text-[9px] font-bold transition-all ${
                            currentPage === i + 1
                              ? 'bg-primary text-primary-foreground shadow-sm'
                              : 'hover:bg-muted text-muted-foreground'
                          }`}
                        >
                          {i + 1}
                        </button>
                      ))}
                    </div>

                    <button
                      onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                      disabled={currentPage === totalPages}
                      className="p-1 rounded bg-background border border-border disabled:opacity-30 hover:bg-muted transition-all"
                    >
                      <ChevronRight className="w-3 h-3" />
                    </button>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default House;

import React, { useState, useEffect } from 'react';
import {
  UserPlus,
  Upload,
  Save,
  ChevronDown,
  Check,
  Plus,
  ArrowLeft,
  Camera,
  X
} from 'lucide-react';
import { useAcademics } from '../../hooks/useAcademics';
import api from '../../lib/api';
import { toast } from 'sonner';
import { Link, useNavigate } from 'react-router-dom';
import CustomSelect from '../../components/ui/CustomSelect';
import CustomDatePicker from '../../components/ui/CustomDatePicker';

const StudentAdmission = () => {
  const { classes, sections } = useAcademics();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [categories, setCategories] = useState([]);
  const [houses, setHouses] = useState([]);
  const [photoFile, setPhotoFile] = useState(null);
  const [photoPreview, setPhotoPreview] = useState(null);
  const [birthCertFile, setBirthCertFile] = useState(null);
  const [birthCertPreview, setBirthCertPreview] = useState(null);

  const [formData, setFormData] = useState({
    enrollNumber: '',
    classId: '',
    sectionId: '',
    categoryId: '',
    firstName: '',
    middleName: '',
    lastName: '',
    gender: '',
    dob: '',
    mobileNumber: '',
    email: '',
    admissionDate: new Date().toISOString().split('T')[0],
    fatherName: '',
    fatherPhone: '',
    motherName: '',
    motherPhone: '',
    guardianIs: 'Father',
    guardianName: '',
    guardianRelation: '',
    guardianPhone: '',
    guardianAddress: ''
  });

  const [isGuardianNameManual, setIsGuardianNameManual] = useState(false);
  const [isGuardianPhoneManual, setIsGuardianPhoneManual] = useState(false);

  // Fetch categories and houses
  useEffect(() => {
    const fetchSetupData = async () => {
      try {
        const [catRes, houseRes] = await Promise.all([
          api.get('/student-setup/categories'),
          api.get('/student-setup/houses')
        ]);
        setCategories(catRes.data.data || []);
        setHouses(houseRes.data.data || []);
      } catch (error) {
        toast.error('Failed to load setup data');
      }
    };
    fetchSetupData();
  }, []);

  // Handle photo selection
  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        toast.error('Photo size should be less than 5MB');
        return;
      }
      setPhotoFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhotoPreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const removePhoto = () => {
    setPhotoFile(null);
    setPhotoPreview(null);
  };

  const handleBirthCertChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        toast.error('File size should be less than 5MB');
        return;
      }
      setBirthCertFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setBirthCertPreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeBirthCert = () => {
    setBirthCertFile(null);
    setBirthCertPreview(null);
  };

  // Sync Guardian Info Smarter
  useEffect(() => {
    if (formData.guardianIs === 'Father') {
      setFormData(prev => ({
        ...prev,
        guardianName: isGuardianNameManual ? prev.guardianName : prev.fatherName,
        guardianPhone: isGuardianPhoneManual ? prev.guardianPhone : prev.fatherPhone,
        guardianRelation: 'Father'
      }));
    } else if (formData.guardianIs === 'Mother') {
      setFormData(prev => ({
        ...prev,
        guardianName: isGuardianNameManual ? prev.guardianName : prev.motherName,
        guardianPhone: isGuardianPhoneManual ? prev.guardianPhone : prev.motherPhone,
        guardianRelation: 'Mother'
      }));
    }
  }, [formData.guardianIs, formData.fatherName, formData.fatherPhone, formData.motherName, formData.motherPhone, isGuardianNameManual, isGuardianPhoneManual]);

  const handleGuardianRoleChange = (role) => {
    setIsGuardianNameManual(false);
    setIsGuardianPhoneManual(false);
    setFormData(prev => ({ ...prev, guardianIs: role }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Validation
    if (!formData.firstName || !formData.gender || !formData.dob ||
        !formData.classId || !formData.sectionId || !formData.guardianName || !formData.guardianPhone) {
      toast.error('Please fill all required fields');
      return;
    }

    if (!birthCertFile) {
      toast.error('Birth certificate is required for admission');
      return;
    }

    setLoading(true);
    try {
      // Create FormData for file upload
      const submitData = new FormData();

      // Append all form fields
      Object.keys(formData).forEach(key => {
        if (formData[key]) {
          submitData.append(key, formData[key]);
        }
      });

      // Append files if selected
      if (photoFile) {
        submitData.append('photo', photoFile);
      }
      if (birthCertFile) {
        submitData.append('birthCertificate', birthCertFile);
      }

      const response = await api.post('/students/admit', submitData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      if (response.data.success) {
        toast.success(response.data.message);
        navigate('/students');
      }
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to admit student');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-in fade-in duration-500 pb-20">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Link to="/students" className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-accent transition-colors">
            <ArrowLeft className="w-4 h-4" />
          </Link>
          <div>
            <h1 className="text-lg font-black text-foreground tracking-tight">Student Admission</h1>
            <p className="text-[11px] text-muted-foreground">Fill in the details to enroll a new student.</p>
          </div>
        </div>
        <button className="flex items-center gap-2 px-3 py-1.5 bg-accent text-foreground rounded-lg text-[11px] font-bold hover:bg-accent/80 transition-all">
          <Upload className="w-3.5 h-3.5" />
          Import Student
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Section 1: Basic Information */}
        <div className="bg-card border border-border rounded-xl shadow-sm">
          <div className="px-4 py-3 border-b border-border bg-muted/10 rounded-t-xl">
            <h3 className="text-xs font-bold text-foreground">Student Admission Details</h3>
          </div>
          <div className="p-5">
            {/* Photo and Birth Certificate Upload */}
            <div className="mb-6 flex items-start gap-6">
              {/* Student Photo */}
              <div className="flex-shrink-0">
                <div className="relative w-32 h-32 border-2 border-dashed border-border rounded-xl overflow-hidden bg-muted/20 flex items-center justify-center group hover:border-primary transition-colors">
                  {photoPreview ? (
                    <>
                      <img src={photoPreview} alt="Preview" className="w-full h-full object-cover" />
                      <button
                        type="button"
                        onClick={removePhoto}
                        className="absolute top-2 right-2 w-6 h-6 bg-destructive text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <X className="w-3.5 h-3.5" />
                      </button>
                    </>
                  ) : (
                    <div className="text-center">
                      <Camera className="w-8 h-8 text-muted-foreground mx-auto mb-2" />
                      <p className="text-[10px] text-muted-foreground">Student Photo</p>
                    </div>
                  )}
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handlePhotoChange}
                    className="absolute inset-0 opacity-0 cursor-pointer"
                  />
                </div>
                <p className="text-[9px] text-muted-foreground mt-2 text-center">Optional</p>
              </div>

              {/* Birth Certificate */}
              <div className="flex-shrink-0">
                <div className="relative w-32 h-32 border-2 border-dashed border-border rounded-xl overflow-hidden bg-muted/20 flex items-center justify-center group hover:border-primary transition-colors">
                  {birthCertPreview ? (
                    <>
                      <img src={birthCertPreview} alt="Birth Certificate" className="w-full h-full object-cover" />
                      <button
                        type="button"
                        onClick={removeBirthCert}
                        className="absolute top-2 right-2 w-6 h-6 bg-destructive text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <X className="w-3.5 h-3.5" />
                      </button>
                    </>
                  ) : (
                    <div className="text-center">
                      <Upload className="w-8 h-8 text-muted-foreground mx-auto mb-2" />
                      <p className="text-[10px] text-muted-foreground">Birth Certificate *</p>
                    </div>
                  )}
                  <input
                    type="file"
                    accept="image/*,application/pdf"
                    onChange={handleBirthCertChange}
                    className="absolute inset-0 opacity-0 cursor-pointer"
                  />
                </div>
                <p className="text-[9px] text-muted-foreground mt-2 text-center">Required</p>
              </div>

              <div className="flex-1 grid grid-cols-1 gap-4">
                <div className="p-4 bg-primary/5 border border-primary/20 rounded-lg">
                  <p className="text-[11px] font-bold text-primary mb-1">Auto-Generated Admission Number</p>
                  <p className="text-[10px] text-muted-foreground">The admission number will be automatically assigned based on the last student's number.</p>
                </div>
                <Input
                  label="Enroll Number (Optional)"
                  value={formData.enrollNumber}
                  onChange={(v) => setFormData({...formData, enrollNumber: v})}
                  placeholder="Government enrollment number"
                />
              </div>
            </div>

            {/* Form Fields */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Class *</label>
                <CustomSelect
                  value={formData.classId}
                  onChange={(v) => setFormData({...formData, classId: v})}
                  options={classes.map(c => ({ id: c.id, label: c.name }))}
                  placeholder="Select Class"
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Section *</label>
                <CustomSelect
                  value={formData.sectionId}
                  onChange={(v) => setFormData({...formData, sectionId: v})}
                  options={sections.map(s => ({ id: s.id, label: s.name }))}
                  placeholder="Select Section"
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Category (Optional)</label>
                <CustomSelect
                  value={formData.categoryId}
                  onChange={(v) => setFormData({...formData, categoryId: v})}
                  options={categories.map(c => ({ id: c.id, label: c.name }))}
                  placeholder="Select Category"
                />
              </div>

              <Input
                label="First Name *"
                value={formData.firstName}
                onChange={(v) => setFormData({...formData, firstName: v})}
                required
                mode="alpha"
              />
              <Input
                label="Middle Name"
                value={formData.middleName}
                onChange={(v) => setFormData({...formData, middleName: v})}
                mode="alpha"
              />
              <Input
                label="Last Name"
                value={formData.lastName}
                onChange={(v) => setFormData({...formData, lastName: v})}
                mode="alpha"
              />

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Gender *</label>
                <CustomSelect
                  value={formData.gender}
                  onChange={(v) => setFormData({...formData, gender: v})}
                  options={[
                    { id: 'Male', label: 'Male' },
                    { id: 'Female', label: 'Female' },
                    { id: 'Other', label: 'Other' }
                  ]}
                  placeholder="Select Gender"
                />
              </div>

              <CustomDatePicker
                label="Date of Birth *"
                value={formData.dob}
                onChange={(v) => setFormData({...formData, dob: v})}
              />
              <Input
                label="Mobile Number"
                value={formData.mobileNumber}
                onChange={(v) => setFormData({...formData, mobileNumber: v})}
                mode="numeric"
              />
              <Input
                label="Email"
                type="email"
                value={formData.email}
                onChange={(v) => setFormData({...formData, email: v})}
              />
              <CustomDatePicker
                label="Admission Date"
                value={formData.admissionDate}
                onChange={(v) => setFormData({...formData, admissionDate: v})}
              />
            </div>
          </div>
        </div>

        {/* Section 2: Parent/Guardian Details */}
        <div className="bg-card border border-border rounded-xl shadow-sm">
          <div className="px-4 py-3 border-b border-border bg-muted/10 rounded-t-xl">
            <h3 className="text-xs font-bold text-foreground">Parent Guardian Detail</h3>
          </div>
          <div className="p-5 space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
              <Input label="Father Name" value={formData.fatherName} onChange={(v) => setFormData({...formData, fatherName: v})} mode="alpha" />
              <Input label="Father Phone" value={formData.fatherPhone} onChange={(v) => setFormData({...formData, fatherPhone: v})} mode="numeric" />
              <Input label="Mother Name" value={formData.motherName} onChange={(v) => setFormData({...formData, motherName: v})} mode="alpha" />
              <Input label="Mother Phone" value={formData.motherPhone} onChange={(v) => setFormData({...formData, motherPhone: v})} mode="numeric" />
            </div>

            <div className="space-y-4 pt-4 border-t border-border">
              <div className="flex items-center gap-6">
                <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">If Guardian Is *</label>
                <div className="flex items-center gap-4">
                  {['Father', 'Mother', 'Other'].map(role => (
                    <label key={role} className="flex items-center gap-2 cursor-pointer group">
                      <input 
                        type="radio" 
                        name="guardianIs" 
                        checked={formData.guardianIs === role}
                        onChange={() => handleGuardianRoleChange(role)}
                        className="hidden"
                      />
                      <div className={`w-3.5 h-3.5 rounded-full border flex items-center justify-center transition-all ${formData.guardianIs === role ? 'border-primary bg-primary' : 'border-border group-hover:border-primary/50'}`}>
                        {formData.guardianIs === role && <div className="w-1 h-1 bg-white rounded-full"></div>}
                      </div>
                      <span className="text-[11px] font-medium text-foreground">{role}</span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
                <Input 
                  label="Guardian Name *" 
                  value={formData.guardianName} 
                  onChange={(v) => {
                    setFormData({...formData, guardianName: v});
                    setIsGuardianNameManual(true);
                  }} 
                  required 
                  mode="alpha" 
                  disabled={formData.guardianIs === 'Father' || formData.guardianIs === 'Mother'}
                />

                {formData.guardianIs === 'Other' && (
                  <Input 
                    label="Guardian Relation" 
                    value={formData.guardianRelation} 
                    onChange={(v) => setFormData({...formData, guardianRelation: v})} 
                    mode="alpha" 
                  />
                )}

                <Input 
                  label="Guardian Phone *" 
                  value={formData.guardianPhone} 
                  onChange={(v) => {
                    setFormData({...formData, guardianPhone: v});
                    setIsGuardianPhoneManual(true);
                  }} 
                  required 
                  mode="numeric" 
                />
                <Input label="Guardian Address" value={formData.guardianAddress} onChange={(v) => setFormData({...formData, guardianAddress: v})} />
              </div>
            </div>
          </div>
        </div>

        {/* Action Bar */}
        <div className="flex items-center justify-end gap-3 pt-2">
          <button 
            type="button" 
            onClick={() => navigate('/students')}
            className="px-6 py-2 border border-border rounded-lg text-xs font-bold hover:bg-accent transition-all"
          >
            Cancel
          </button>
          <button 
            type="submit"
            disabled={loading}
            className="flex items-center gap-2 px-8 py-2 bg-primary text-primary-foreground rounded-lg text-xs font-bold shadow-lg shadow-primary/20 hover:opacity-90 transition-all disabled:opacity-50"
          >
            {loading ? <div className="w-3.5 h-3.5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <Save className="w-3.5 h-3.5" />}
            Save Student
          </button>
        </div>
      </form>
    </div>
  );
};

const Input = ({ label, type = 'text', value, onChange, required = false, mode = 'any', disabled = false }) => {
  const handleChange = (val) => {
    if (disabled) return;
    if (mode === 'numeric') {
      // Only allow digits
      const cleaned = val.replace(/[^0-9]/g, '');
      onChange(cleaned);
    } else if (mode === 'alpha') {
      // Only allow letters and spaces
      const cleaned = val.replace(/[^a-zA-Z\s]/g, '');
      onChange(cleaned);
    } else {
      onChange(val);
    }
  };

  return (
    <div className="space-y-1.5">
      <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1">{label}</label>
      <input 
        type={type}
        value={value}
        onChange={(e) => handleChange(e.target.value)}
        required={required}
        disabled={disabled}
        className={`w-full h-9 bg-muted/30 border border-border rounded-lg px-3 text-xs focus:outline-none focus:ring-1 focus:ring-primary/20 transition-all ${disabled ? 'opacity-60 cursor-not-allowed bg-muted/50' : ''}`}
      />
    </div>
  );
};

export default StudentAdmission;

import React, { useState, useEffect } from 'react';
import { 
  Search, 
  Filter, 
  List, 
  LayoutGrid, 
  MoreVertical, 
  UserPlus, 
  FileEdit, 
  Trash2, 
  Eye,
  ArrowRight,
  FolderOpen,
  Check,
  ChevronDown,
  X,
  Phone,
  Mail,
  Calendar,
  MapPin,
  ChevronLeft,
  ChevronRight
} from 'lucide-react';
import { useStudents } from '../../hooks/useStudents';
import { useAcademics } from '../../hooks/useAcademics';
import { Link } from 'react-router-dom';
import CustomSelect from '../../components/ui/CustomSelect';

const StudentDetails = () => {
  const { students, loading, fetchStudents } = useStudents();
  const { classes, sections } = useAcademics();
  
  const [activeTab, setActiveTab] = useState('list'); // 'list' or 'details'
  const [filters, setFilters] = useState({
    classId: '',
    sectionId: '',
    search: ''
  });

  const [selectedStudent, setSelectedStudent] = useState(null);
  const [showViewModal, setShowViewModal] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const handleSearch = () => {
    setCurrentPage(1);
    fetchStudents(filters);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this student?')) return;
    try {
      await api.delete(`/students/${id}`);
      toast.success('Student deleted successfully');
      fetchStudents(filters);
    } catch (err) {
      toast.error('Failed to delete student');
    }
  };

  const handleView = (student) => {
    setSelectedStudent(student);
    setShowViewModal(true);
  };

  // Initial fetch
  useEffect(() => {
    fetchStudents();
  }, [fetchStudents]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header Area */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-lg font-black text-foreground tracking-tight">Student Details</h1>
          <p className="text-[11px] text-muted-foreground">Manage and view detailed information about your students.</p>
        </div>
        <Link 
          to="/students/admission"
          className="flex items-center gap-2 px-3.5 py-2 bg-primary text-primary-foreground rounded-lg text-xs font-bold shadow-lg shadow-primary/10 hover:opacity-90 transition-all active:scale-95"
        >
          <UserPlus className="w-3.5 h-3.5" />
          Admit Student
        </Link>
      </div>

      {/* Filter Section */}
      <div className="bg-card border border-border rounded-xl p-4 shadow-sm">
        <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-4 items-end">
          <div className="space-y-1.5">
            <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Class *</label>
            <CustomSelect 
              value={filters.classId}
              onChange={(val) => setFilters({...filters, classId: val})}
              options={classes.map(c => ({ id: c.id, label: c.name }))}
              placeholder="Select Class"
            />
          </div>

          <div className="space-y-1.5">
            <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Section</label>
            <CustomSelect 
              value={filters.sectionId}
              onChange={(val) => setFilters({...filters, sectionId: val})}
              options={sections.map(s => ({ id: s.id, label: s.name }))}
              placeholder="Select Section"
            />
          </div>

          <div className="space-y-1.5 lg:col-span-1">
            <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest ml-1">Search By Keyword</label>
            <div className="relative">
              <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-muted-foreground" />
              <input 
                type="text"
                placeholder="Name, Roll No..."
                value={filters.search}
                onChange={(e) => setFilters({...filters, search: e.target.value})}
                className="w-full h-9 bg-muted/30 border border-border rounded-lg pl-8 pr-3 text-xs focus:outline-none focus:ring-1 focus:ring-primary/20 transition-all"
              />
            </div>
          </div>

          <button 
            onClick={handleSearch}
            className="h-9 bg-foreground text-background rounded-lg px-5 font-bold text-xs hover:opacity-90 transition-all active:scale-95 flex items-center justify-center gap-2"
          >
            <Filter className="w-3.5 h-3.5" />
            Search
          </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="bg-card border border-border rounded-xl shadow-sm">
        {/* Tabs */}
        <div className="flex border-b border-border bg-muted/10 px-2 rounded-t-xl overflow-hidden">
          <button 
            onClick={() => setActiveTab('list')}
            className={`flex items-center gap-2 px-4 py-3 text-[11px] font-bold transition-all relative ${activeTab === 'list' ? 'text-primary' : 'text-muted-foreground hover:text-foreground'}`}
          >
            <List className="w-3.5 h-3.5" />
            List View
            {activeTab === 'list' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-primary rounded-t-full mx-2"></div>}
          </button>
          <button 
            onClick={() => setActiveTab('details')}
            className={`flex items-center gap-2 px-4 py-3 text-[11px] font-bold transition-all relative ${activeTab === 'details' ? 'text-primary' : 'text-muted-foreground hover:text-foreground'}`}
          >
            <LayoutGrid className="w-3.5 h-3.5" />
            Details View
            {activeTab === 'details' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-primary rounded-t-full mx-2"></div>}
          </button>
        </div>

        {/* View Switcher */}
        <div className="p-0 text-xs">
          {loading ? (
            <div className="p-16 flex flex-col items-center justify-center space-y-3">
              <div className="w-8 h-8 border-3 border-primary/10 border-t-primary rounded-full animate-spin"></div>
              <p className="text-[11px] font-bold text-muted-foreground">Syncing data...</p>
            </div>
          ) : students.length > 0 ? (
            activeTab === 'list' ? (
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-muted/20 border-b border-border">
                      <th className="px-5 py-3 text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Admission</th>
                      <th className="px-5 py-3 text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Student</th>
                      <th className="px-5 py-3 text-[10px] font-bold text-muted-foreground uppercase tracking-wider text-center">Roll</th>
                      <th className="px-5 py-3 text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Academic</th>
                      <th className="px-5 py-3 text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Parent</th>
                      <th className="px-5 py-3 text-[10px] font-bold text-muted-foreground uppercase tracking-wider">DOB</th>
                      <th className="px-5 py-3 text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Contact</th>
                      <th className="px-5 py-3 text-[10px] font-bold text-muted-foreground uppercase tracking-wider text-right"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-border">
                    {students.map((student) => (
                      <tr key={student.id} className="hover:bg-muted/5 transition-colors group">
                        <td className="px-5 py-3 text-[11px] font-bold text-primary">{student.admissionNo}</td>
                        <td className="px-5 py-3">
                          <span className="text-[12px] font-bold text-foreground">{student.firstName} {student.lastName}</span>
                        </td>
                        <td className="px-5 py-3 text-[11px] text-center font-medium text-muted-foreground">{student.rollNumber || '--'}</td>
                        <td className="px-5 py-3 text-[11px] text-muted-foreground">
                          {student.Class?.name} • {student.Section?.name}
                        </td>
                        <td className="px-5 py-3 text-[11px] text-muted-foreground">{student.fatherName || '--'}</td>
                        <td className="px-5 py-3 text-[11px] text-muted-foreground italic">
                          {student.dob ? new Date(student.dob).toLocaleDateString('en-GB', { day: '2-digit', month: 'short' }) : '--'}
                        </td>
                        <td className="px-5 py-3 text-[11px] text-muted-foreground">{student.mobileNumber || '--'}</td>
                        <td className="px-5 py-3 text-right">
                          <div className="flex items-center justify-end gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button onClick={() => handleView(student)} title="View" className="p-1.5 hover:bg-accent rounded text-muted-foreground hover:text-primary transition-all"><Eye className="w-3.5 h-3.5" /></button>
                            <Link to={`/students/edit/${student.id}`} title="Edit" className="p-1.5 hover:bg-accent rounded text-muted-foreground hover:text-foreground transition-all"><FileEdit className="w-3.5 h-3.5" /></Link>
                            <button onClick={() => handleDelete(student.id)} title="Delete" className="p-1.5 hover:bg-accent rounded text-muted-foreground hover:text-destructive transition-all"><Trash2 className="w-3.5 h-3.5" /></button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 p-4 bg-muted/5">
                {students.map((student) => (
                  <div key={student.id} className="bg-card border border-border rounded-xl p-4 hover:shadow-lg transition-all hover:-translate-y-0.5 group">
                    <div className="flex items-start justify-between mb-3">
                      <div className="w-12 h-12 bg-accent rounded-lg flex items-center justify-center text-foreground font-black text-sm border border-border overflow-hidden">
                        {student.photo ? <img src={student.photo} alt="" className="w-full h-full object-cover" /> : student.firstName.charAt(0)}
                      </div>
                      <div className="px-2 py-0.5 bg-primary/10 text-primary rounded-md text-[9px] font-black uppercase tracking-tighter border border-primary/10">
                        {student.admissionNo}
                      </div>
                    </div>
                    <h4 className="text-[13px] font-bold text-foreground mb-0.5 truncate">{student.firstName} {student.lastName}</h4>
                    <p className="text-[10px] text-muted-foreground font-bold mb-3">{student.Class?.name} • {student.Section?.name}</p>
                    
                    <div className="space-y-1.5 border-t border-border pt-3 mb-3">
                      <div className="flex justify-between text-[9px]">
                        <span className="text-muted-foreground/50 font-bold uppercase tracking-tight">Parent</span>
                        <span className="text-foreground font-bold truncate ml-2">{student.fatherName || '--'}</span>
                      </div>
                    </div>

                    <div className="flex items-center gap-1.5">
                      <button className="flex-1 py-1.5 bg-accent hover:bg-accent/80 text-foreground text-[10px] font-bold rounded-lg transition-all">Profile</button>
                      <button className="w-7 h-7 flex items-center justify-center bg-muted hover:bg-accent text-muted-foreground hover:text-foreground rounded-lg transition-all">
                        <MoreVertical className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )
          ) : (
            <div className="p-16 flex flex-col items-center justify-center text-center space-y-4">
                <div className="w-16 h-16 bg-muted/30 rounded-full flex items-center justify-center">
                  <FolderOpen className="w-7 h-7 text-muted-foreground/20" />
                </div>
                <div className="max-w-[200px] space-y-1">
                  <h3 className="text-sm font-bold text-foreground">No records found</h3>
                  <p className="text-[11px] text-muted-foreground">Adjust filters or search parameters.</p>
                </div>
                <Link 
                  to="/students/admission"
                  className="flex items-center gap-1.5 text-primary text-[11px] font-bold hover:gap-2 transition-all"
                >
                  New record <ArrowRight className="w-3.5 h-3.5" />
                </Link>
              </div>
            )}
          </div>
          
          {/* Pagination */}
          {!loading && students.length > 0 && (
            <div className="px-5 py-3 bg-muted/5 border-t border-border flex items-center justify-between">
              <p className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest">
                Showing {students.length} Students
              </p>
            </div>
          )}
        </div>

        {/* View Modal */}
        {showViewModal && selectedStudent && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="absolute inset-0 bg-background/80 backdrop-blur-md" onClick={() => setShowViewModal(false)}></div>
            <div className="relative bg-card border border-border w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
              {/* Modal Header */}
              <div className="px-6 py-4 border-b border-border bg-muted/10 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-primary/10 rounded-xl flex items-center justify-center text-primary">
                    <Eye className="w-5 h-5" />
                  </div>
                  <div>
                    <h3 className="text-sm font-black text-foreground tracking-tight">Student Profile</h3>
                    <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-widest">Admission No: {selectedStudent.admissionNo}</p>
                  </div>
                </div>
                <button onClick={() => setShowViewModal(false)} className="p-2 hover:bg-accent rounded-lg transition-colors">
                  <X className="w-4 h-4" />
                </button>
              </div>

              {/* Modal Body */}
              <div className="p-6 space-y-6 max-h-[70vh] overflow-y-auto hide-scrollbar">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {/* Left: Personal */}
                  <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-primary uppercase tracking-widest border-b border-primary/10 pb-1">Personal Details</h4>
                    <div className="space-y-3">
                      <DetailItem label="Full Name" value={`${selectedStudent.firstName} ${selectedStudent.lastName}`} icon={<List className="w-3 h-3" />} />
                      <DetailItem label="Gender" value={selectedStudent.gender} icon={<UserPlus className="w-3 h-3" />} />
                      <DetailItem label="Date of Birth" value={selectedStudent.dob ? new Date(selectedStudent.dob).toLocaleDateString() : '--'} icon={<Calendar className="w-3 h-3" />} />
                      <DetailItem label="Email" value={selectedStudent.email || 'N/A'} icon={<Mail className="w-3 h-3" />} />
                      <DetailItem label="Mobile" value={selectedStudent.mobileNumber || 'N/A'} icon={<Phone className="w-3 h-3" />} />
                    </div>
                  </div>

                  {/* Right: Academic & Guardian */}
                  <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-primary uppercase tracking-widest border-b border-primary/10 pb-1">Academic & Guardian</h4>
                    <div className="space-y-3">
                      <DetailItem label="Class & Section" value={`${selectedStudent.class?.name} - ${selectedStudent.section?.name}`} icon={<LayoutGrid className="w-3 h-3" />} />
                      <DetailItem label="Roll Number" value={selectedStudent.rollNumber || '--'} icon={<Check className="w-3 h-3" />} />
                      <DetailItem label="Father's Name" value={selectedStudent.fatherName || '--'} icon={<UserPlus className="w-3 h-3" />} />
                      <DetailItem label="Guardian Name" value={selectedStudent.guardianName || '--'} icon={<UserPlus className="w-3 h-3" />} />
                      <DetailItem label="Guardian Phone" value={selectedStudent.guardianPhone || '--'} icon={<Phone className="w-3 h-3" />} />
                    </div>
                  </div>
                </div>

                {/* Address */}
                <div className="pt-4 border-t border-border">
                  <DetailItem label="Guardian Address" value={selectedStudent.guardianAddress || 'No address provided'} icon={<MapPin className="w-3 h-3" />} fullWidth />
                </div>
              </div>

              {/* Modal Footer */}
              <div className="px-6 py-4 bg-muted/10 border-t border-border flex justify-end gap-3">
                <button onClick={() => setShowViewModal(false)} className="px-4 py-2 bg-accent text-foreground text-xs font-bold rounded-lg hover:bg-accent/80 transition-all">Close</button>
                <Link to={`/students/edit/${selectedStudent.id}`} className="px-4 py-2 bg-primary text-primary-foreground text-xs font-bold rounded-lg shadow-lg shadow-primary/10 hover:opacity-90 transition-all flex items-center gap-2">
                  <FileEdit className="w-3.5 h-3.5" /> Edit Profile
                </Link>
              </div>
            </div>
          </div>
      )}
    </div>
  );
};
const DetailItem = ({ label, value, icon, fullWidth = false }) => (
  <div className={`flex flex-col gap-1 ${fullWidth ? 'w-full' : ''}`}>
    <span className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest flex items-center gap-1.5">
      {icon} {label}
    </span>
    <span className="text-[11px] font-bold text-foreground bg-muted/20 px-2 py-1 rounded border border-border/50">{value}</span>
  </div>
);

export default StudentDetails;

