            <h2 className="text-xs font-black uppercase tracking-wider text-foreground">Class Teacher Responsibilities</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {data.classTeacherOf.map((c, i) => (
              <div key={i} className="bg-gradient-to-br from-primary/10 to-primary/5 border border-primary/20 rounded-xl p-4 space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-sm font-bold text-foreground">Class {c.Class?.name} - {c.Section?.name}</h3>
                    <p className="text-[10px] text-primary uppercase font-bold tracking-widest">Designated Class Teacher</p>
                  </div>
                  <Star className="w-5 h-5 text-primary fill-primary" />
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <Link
                    to={`/teacher/attendance?classId=${c.classId}&sectionId=${c.sectionId}`}
                    className="flex items-center justify-center gap-2 h-9 bg-primary text-primary-foreground rounded-lg text-xs font-bold hover:opacity-90"
                  >
                    <ClipboardList className="w-4 h-4" />
                    Attendance
                  </Link>
                  <Link
                    to={`/teacher/class-overview`}
                    className="flex items-center justify-center gap-2 h-9 bg-card border border-border text-foreground hover:bg-muted rounded-lg text-xs font-bold"
                  >
                    <Users className="w-4 h-4" />
                    Overview
                  </Link>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Teaching Classes */}
      <div className="space-y-3">
        <h2 className="text-xs font-black uppercase tracking-wider text-muted-foreground">Taught Classes</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {(data.classes || data.teachingClasses || [])?.length === 0 ? (
            <div className="bg-card border border-border rounded-xl p-6 text-center text-muted-foreground md:col-span-3">
              No teaching classes found in your timetable schedule.
            </div>
          ) : (
            (data.classes || data.teachingClasses || []).map((item, index) => (
              <div key={index} className="bg-card border border-border hover:border-primary/20 rounded-xl p-4 space-y-4 transition-all">
                <div>
                  <h3 className="text-sm font-bold text-foreground">Class {item.Class?.name} - {item.Section?.name}</h3>
                  <p className="text-[10px] text-muted-foreground">
                    {item.isClassTeacher ? 'Class Teacher' : 'Subject Teaching Slot'}
                    {item.periodCount ? ` - ${item.periodCount} weekly periods` : ''}
                  </p>
                  {item.Subjects?.length > 0 && (
                    <div className="flex flex-wrap gap-1.5 mt-2">
                      {item.Subjects.slice(0, 4).map(subject => (
                        <span key={subject.id} className="text-[9px] bg-primary/10 text-primary border border-primary/20 px-2 py-0.5 rounded-full font-bold">
                          {subject.name}
                        </span>
                      ))}
                      {item.Subjects.length > 4 && (
                        <span className="text-[9px] bg-muted text-muted-foreground border border-border px-2 py-0.5 rounded-full font-bold">
                          +{item.Subjects.length - 4}
                        </span>
                      )}
                    </div>
                  )}
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <Link
                    to={`/teacher/attendance?classId=${item.classId}&sectionId=${item.sectionId}`}
                    className="flex items-center justify-center gap-1.5 h-8 bg-muted text-foreground hover:bg-accent rounded-lg text-[10px] font-bold"
                  >
                    <ClipboardList className="w-3.5 h-3.5" />
                    Attendance
                  </Link>
                  <Link
                    to={`/teacher/marks?classId=${item.classId}&sectionId=${item.sectionId}`}
                    className="flex items-center justify-center gap-1.5 h-8 bg-muted text-foreground hover:bg-accent rounded-lg text-[10px] font-bold"
                  >
                    <Award className="w-3.5 h-3.5" />
                    Marks
                  </Link>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default MyClasses;

import React, { useState, useEffect } from 'react';
import { Calendar, Clock, BookOpen, MapPin } from 'lucide-react';
import api from '../../lib/api';
import { toast } from 'sonner';

const MySchedule = () => {
  const [schedule, setSchedule] = useState({});
  const [loading, setLoading] = useState(true);
  const [activeDay, setActiveDay] = useState('');

  const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

  useEffect(() => {
    const fetchSchedule = async () => {
      try {
        const response = await api.get('/teacher/schedule');
        if (response.data.data) {
          setSchedule(response.data.data.grouped || {});

          // Set current day as active day default
          const today = new Date().toLocaleDateString('en-US', { weekday: 'long' });
          setActiveDay(days.includes(today) ? today : 'Monday');
        }
      } catch (error) {
        toast.error('Failed to load timetable schedule');
      } finally {
        setLoading(false);
      }
    };
    fetchSchedule();
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="flex flex-col items-center gap-2">
          <div className="w-8 h-8 border-3 border-primary/20 border-t-primary rounded-full animate-spin"></div>
          <span className="text-[10px] font-bold text-primary uppercase tracking-widest">Loading timetable...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500 max-w-[1200px] mx-auto">
      <div>
        <h1 className="text-xl font-black text-foreground tracking-tight flex items-center gap-2">
          <Calendar className="w-5 h-5 text-primary" /> My Timetable
        </h1>
        <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold opacity-70">
          Your weekly teaching schedule and class timings
        </p>
      </div>

      {/* Days Tabs selector */}
      <div className="flex flex-wrap gap-2 border-b border-border pb-3">
        {days.map((day) => {
          const count = schedule[day]?.length || 0;
          const isActive = activeDay === day;
          return (
            <button
              key={day}
              onClick={() => setActiveDay(day)}
              className={`px-4 py-2 text-xs font-bold rounded-lg transition-all flex items-center gap-2 ${
                isActive 
                  ? 'bg-primary text-primary-foreground shadow-sm' 
                  : 'bg-card border border-border text-muted-foreground hover:text-foreground'
              }`}
            >
              {day}
              {count > 0 && (
                <span className={`text-[9px] px-1.5 py-0.5 rounded-full ${
                  isActive ? 'bg-primary-foreground text-primary' : 'bg-muted text-muted-foreground'
                }`}>
                  {count}
                </span>
              )}
            </button>
          );
        })}
      </div>

      {/* Timetable schedule content */}
      <div className="grid grid-cols-1 gap-3">
        {!schedule[activeDay] || schedule[activeDay].length === 0 ? (
          <div className="bg-card border border-border rounded-xl p-8 text-center text-muted-foreground">
            <BookOpen className="w-8 h-8 mx-auto mb-2 opacity-30" />
            <p className="text-xs font-bold uppercase tracking-wider">No classes scheduled for {activeDay}</p>
          </div>
        ) : (
          schedule[activeDay].map((slot, index) => (
            <div 
              key={index} 
              className="bg-card border border-border hover:border-primary/20 rounded-xl p-4 flex flex-col md:flex-row md:items-center justify-between gap-4 transition-all"
            >
              <div className="flex items-center gap-3">
                <div className="p-3 bg-primary/10 text-primary border border-primary/20 rounded-xl flex-shrink-0">
                  <Clock className="w-5 h-5" />
                </div>
                <div>
                  <h3 className="text-sm font-bold text-foreground">{slot.Subject?.name || 'Subject'}</h3>
                  <p className="text-xs text-muted-foreground">
                    Class {slot.Class?.name} - {slot.Section?.name}
                  </p>
                </div>
              </div>

              <div className="flex items-center gap-6">
                <div className="flex items-center gap-2 text-xs text-muted-foreground font-bold">
                  <Clock className="w-4 h-4 text-primary" />
                  {slot.startTime} - {slot.endTime}
                </div>
                {slot.roomNo && (
                  <div className="flex items-center gap-2 text-xs text-muted-foreground font-bold">
                    <MapPin className="w-4 h-4 text-primary" />
                    Room {slot.roomNo}
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default MySchedule;

import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { ClipboardList, Calendar, Users, Save } from 'lucide-react';
import api from '../../lib/api';
import { toast } from 'sonner';
import { DatePicker } from "@/components/ui/date-picker";

const TakeAttendance = () => {
  const [searchParams] = useSearchParams();
  const [classes, setClasses] = useState([]);
  const [selectedClass, setSelectedClass] = useState('');
  const [selectedSection, setSelectedSection] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [students, setStudents] = useState([]);
  const [attendanceData, setAttendanceData] = useState({});
  const [loadingClasses, setLoadingClasses] = useState(true);
  const [loadingStudents, setLoadingStudents] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  // Fetch teaching classes to populate selectors
  useEffect(() => {
    const fetchClasses = async () => {
      try {
        const response = await api.get('/teacher/classes');
        if (response.data.data) {
          const uniqueCombos = response.data.data.classes || [];
          setClasses(uniqueCombos);

          // Select defaults from URL or first option
          const urlClassId = searchParams.get('classId');
          const urlSectionId = searchParams.get('sectionId');

          if (urlClassId && urlSectionId) {
            setSelectedClass(urlClassId);
            setSelectedSection(urlSectionId);
          } else if (uniqueCombos.length > 0) {
            setSelectedClass(uniqueCombos[0].classId);
            setSelectedSection(uniqueCombos[0].sectionId);
          }
        }
      } catch (error) {
        toast.error('Failed to load classes');
      } finally {
        setLoadingClasses(false);
      }
    };
    fetchClasses();
  }, [searchParams]);

  // Load students and active attendance on class/section/date selection
  useEffect(() => {
    if (!selectedClass || !selectedSection) return;

    const loadData = async () => {
      try {
        setLoadingStudents(true);
        // 1. Get students in class
        const studentsRes = await api.get(`/teacher/students?classId=${selectedClass}&sectionId=${selectedSection}`);
        const studentsList = studentsRes.data.data || [];
        setStudents(studentsList);

        // 2. Get existing attendance for this date
        const attendanceRes = await api.get(`/teacher/attendance?classId=${selectedClass}&sectionId=${selectedSection}&date=${date}`);
        const existingAttendance = attendanceRes.data.data || [];

        // Build status map
        const stateMap = {};
        studentsList.forEach(s => {
          const record = existingAttendance.find(a => a.studentId === s.id);
          stateMap[s.id] = {
            status: record ? record.status : 'Present', // Default to present
            note: record ? (record.note || '') : ''
          };
        });
        setAttendanceData(stateMap);
      } catch (error) {
        toast.error('Failed to load class roster or attendance logs');
      } finally {
        setLoadingStudents(false);
      }
    };
    loadData();
  }, [selectedClass, selectedSection, date]);

  const handleStatusChange = (studentId, status) => {
    setAttendanceData(prev => ({
      ...prev,
      [studentId]: { ...prev[studentId], status }
    }));
  };

  const handleNoteChange = (studentId, note) => {
    setAttendanceData(prev => ({
      ...prev,
      [studentId]: { ...prev[studentId], note }
    }));
  };

  const handleClassSelection = (e) => {
    const val = e.target.value;
    if (!val) return;
    const [cId, sId] = val.split(':');
    setSelectedClass(cId);
    setSelectedSection(sId);
  };

  const handleSetAll = (status) => {
    setAttendanceData(prev => {
      const updated = { ...prev };
      Object.keys(updated).forEach(id => {
        updated[id] = { ...updated[id], status };
      });
      return updated;
    });
    toast.success(`Marked all students as ${status}`);
  };

  const handleSubmit = async () => {
    try {
      setSubmitting(true);
      const payload = {
        date,
        classId: selectedClass,
        sectionId: selectedSection,
        attendances: Object.keys(attendanceData).map(studentId => ({
          studentId,
          status: attendanceData[studentId].status,
          note: attendanceData[studentId].note
        }))
      };

      await api.post('/teacher/attendance', payload);
      toast.success('Attendance saved successfully');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to submit attendance');
    } finally {
      setSubmitting(false);
    }
  };

  if (loadingClasses) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="flex flex-col items-center gap-2">
          <div className="w-8 h-8 border-3 border-primary/20 border-t-primary rounded-full animate-spin"></div>
          <span className="text-[10px] font-bold text-primary uppercase tracking-widest">Loading setup...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500 max-w-[1200px] mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-xl font-black text-foreground tracking-tight flex items-center gap-2">
            <ClipboardList className="w-5 h-5 text-primary" /> Daily Attendance Desk
          </h1>
          <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold opacity-70">
            Log student daily attendance, lateness, and notes
          </p>
        </div>

        {/* Filters Panel */}
        <div className="flex flex-wrap items-center gap-3 bg-card border border-border rounded-xl p-3">
          <div className="space-y-1">
            <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest block">Class & Section</label>
            <select
              value={`${selectedClass}:${selectedSection}`}
              onChange={handleClassSelection}
              className="bg-muted/30 border border-border rounded-lg h-9 px-2 text-xs font-bold focus:outline-none"
            >
              {classes.map((c, i) => (
                <option key={i} value={`${c.classId}:${c.sectionId}`}>
                  Class {c.Class?.name} - {c.Section?.name}
                </option>
              ))}
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest block">Date</label>
            <div className="flex items-center gap-2 border border-border rounded-lg bg-muted/30 h-9 px-2.5">
              <Calendar className="w-3.5 h-3.5 text-muted-foreground" />
              <DatePicker
                value={date}
                max={new Date().toISOString().split('T')[0]}
                onChange={(e) => setDate(e.target.value)}
                className="bg-transparent border-none text-xs font-bold focus:outline-none"
              />
            </div>
          </div>
        </div>
      </div>

      {/* Grid Controls */}
      {students.length > 0 && (
        <div className="flex flex-wrap items-center justify-between gap-3 bg-card border border-border rounded-xl p-3">
          <div className="flex items-center gap-2">
            <Users className="w-4 h-4 text-primary" />
            <span className="text-xs font-bold text-foreground">{students.length} Enrolled Students</span>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => handleSetAll('Present')}
              className="px-3 h-8 bg-emerald-500/10 text-emerald-500 border border-emerald-500/20 hover:bg-emerald-500/20 text-[10px] font-black uppercase tracking-wider rounded-lg transition-all"
            >
              All Present
            </button>
            <button
              onClick={() => handleSetAll('Absent')}
              className="px-3 h-8 bg-red-500/10 text-red-500 border border-red-500/20 hover:bg-red-500/20 text-[10px] font-black uppercase tracking-wider rounded-lg transition-all"
            >
              All Absent
            </button>
          </div>
        </div>
      )}

      {/* Roster Listing */}
      {loadingStudents ? (
        <div className="flex items-center justify-center py-20">
          <div className="w-6 h-6 border-2 border-primary/20 border-t-primary rounded-full animate-spin"></div>
        </div>
      ) : students.length === 0 ? (
        <div className="bg-card border border-border rounded-xl p-12 text-center text-muted-foreground">
          <Users className="w-10 h-10 mx-auto mb-2 opacity-30" />
          <p className="text-xs font-bold uppercase tracking-wider">No active students found in this section</p>
        </div>
      ) : (
        <div className="space-y-4">
          <div className="bg-card border border-border rounded-xl overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="border-b border-border bg-muted/10">
                    <th className="p-3 text-[10px] font-bold text-muted-foreground uppercase tracking-widest w-16">Roll No</th>
                    <th className="p-3 text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Student</th>
                    <th className="p-3 text-[10px] font-bold text-muted-foreground uppercase tracking-widest w-72 text-center">Status</th>
                    <th className="p-3 text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Note / Remark</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {students.map((student) => {
                    const current = attendanceData[student.id] || { status: 'Present', note: '' };
                    return (
                      <tr key={student.id} className="hover:bg-muted/10 transition-colors">
                        <td className="p-3 text-xs font-black text-foreground">
                          {student.rollNumber || student.admissionNo.slice(-3)}
                        </td>
                        <td className="p-3">
                          <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded-full bg-muted overflow-hidden flex items-center justify-center font-bold text-xs">
                              {student.photo ? (
                                <img src={student.photo} alt="" className="w-full h-full object-cover" />
                              ) : (
                                student.firstName.charAt(0)
                              )}
                            </div>
                            <div>
                              <p className="text-xs font-bold text-foreground">
                                {student.firstName} {student.lastName}
                              </p>
                              <p className="text-[9px] text-muted-foreground font-bold">Admin No: {student.admissionNo}</p>
                            </div>
                          </div>
                        </td>
                        <td className="p-3">
                          <div className="flex justify-center items-center gap-1 bg-muted/20 border border-border p-1 rounded-xl w-fit mx-auto">
                            {['Present', 'Absent', 'Late', 'HalfDay'].map((st) => {
                              const active = current.status === st;
                              let themeClasses = 'text-muted-foreground hover:text-foreground';
                              if (active) {
                                if (st === 'Present') themeClasses = 'bg-emerald-500 text-white shadow-sm';
                                if (st === 'Absent') themeClasses = 'bg-red-500 text-white shadow-sm';
                                if (st === 'Late') themeClasses = 'bg-amber-500 text-white shadow-sm';
                                if (st === 'HalfDay') themeClasses = 'bg-blue-500 text-white shadow-sm';
                              }
                              return (
                                <button
                                  key={st}
                                  onClick={() => handleStatusChange(student.id, st)}
                                  className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider transition-all ${themeClasses}`}
                                >
                                  {st === 'HalfDay' ? 'Half Day' : st}
                                </button>
                              );
                            })}
                          </div>
                        </td>
                        <td className="p-3">
                          <input
                            type="text"
                            placeholder="Add brief note..."
                            value={current.note}
                            onChange={(e) => handleNoteChange(student.id, e.target.value)}
                            className="w-full bg-muted/20 hover:bg-muted/45 focus:bg-background border border-border hover:border-primary/20 focus:border-primary/55 rounded-lg px-3 h-8 text-xs transition-all focus:outline-none"
                          />
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          {/* Submit Action */}
          <div className="flex justify-end">
            <button
              onClick={handleSubmit}
              disabled={submitting}
              className="flex items-center gap-2 bg-primary text-primary-foreground hover:opacity-90 px-6 h-10 rounded-xl text-xs font-black uppercase tracking-wider disabled:opacity-50 shadow-md transition-all"
            >
              {submitting ? (
                <>Saving Attendance...</>
              ) : (
                <>
                  <Save className="w-4 h-4" />
                  Save Attendance
                </>
              )}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default TakeAttendance;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { BookOpen, Clock, Users, ClipboardList, TrendingUp, Star, ChevronRight, CheckCircle, Calendar, Award } from 'lucide-react';
import api from '../../lib/api';
import { toast } from 'sonner';

const TeacherDashboard = () => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await api.get('/teacher/dashboard');
        setData(res.data.data);
      } catch (e) {
        toast.error('Failed to load dashboard');
      } finally {
        setLoading(false);
      }
    };
    fetch();
  }, []);

  if (loading) return <LoadingScreen />;

  const { staff, isClassTeacher, classTeacherOf, myStudentCount, todaySchedule, pendingHomework, todayAttendance } = data || {};

  const present = todayAttendance?.find(a => a.status === 'Present')?._count?.status || 0;
  const absent = todayAttendance?.find(a => a.status === 'Absent')?._count?.status || 0;
  const late = todayAttendance?.find(a => a.status === 'Late')?._count?.status || 0;
  const halfDay = todayAttendance?.find(a => a.status === 'HalfDay')?._count?.status || 0;
  const markedToday = present + absent + late + halfDay;

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-2xl font-black text-foreground tracking-tight">
            Good {getGreeting()}, {staff?.firstName || 'Teacher'}
          </h1>
          <p className="text-sm text-muted-foreground mt-1">
            {new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
          </p>
        </div>
        {isClassTeacher && (
          <div className="flex items-center gap-2 bg-primary/10 text-primary border border-primary/20 px-3 py-1.5 rounded-xl">
            <Star className="w-4 h-4 fill-primary" />
            <span className="text-xs font-black">Class Teacher - {classTeacherOf?.Class?.name}-{classTeacherOf?.Section?.name}</span>
          </div>
        )}
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard icon={<Clock />} label="Classes Today" value={todaySchedule?.length || 0} color="blue" />
        {isClassTeacher && <StatCard icon={<Users />} label="My Students" value={myStudentCount || 0} color="emerald" />}
        <StatCard icon={<ClipboardList />} label="Pending HW" value={pendingHomework?.length || 0} color="amber" />
        {isClassTeacher && markedToday > 0 && (
          <StatCard icon={<CheckCircle />} label="Marked Today" value={`${present}P / ${absent}A / ${halfDay}H`} color="purple" />
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Today's Schedule */}
        <div className="lg:col-span-2 bg-card border border-border rounded-2xl overflow-hidden">
          <div className="flex items-center justify-between px-5 py-4 border-b border-border">
            <div className="flex items-center gap-2">
              <Calendar className="w-4 h-4 text-primary" />
              <h3 className="text-sm font-black text-foreground">Today's Schedule</h3>
            </div>
            <Link to="/teacher/schedule" className="text-[10px] font-bold text-primary hover:opacity-80 flex items-center gap-1">
              Full Schedule <ChevronRight className="w-3 h-3" />
            </Link>
          </div>
          <div className="divide-y divide-border">
            {todaySchedule?.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 text-muted-foreground">
                <CheckCircle className="w-8 h-8 mb-2 opacity-30" />
                <p className="text-xs font-bold">No classes today!</p>
              </div>
            ) : (
              todaySchedule?.map((slot, i) => (
                <ScheduleRow key={i} slot={slot} />
              ))
            )}
          </div>
        </div>

        {/* Right Column */}
        <div className="space-y-4">
          {/* Class Teacher Quick Actions */}
          {isClassTeacher && (
            <div className="bg-gradient-to-br from-primary/10 to-primary/5 border border-primary/20 rounded-2xl p-4">
              <div className="flex items-center gap-2 mb-3">
                <Star className="w-4 h-4 text-primary fill-primary" />
                <h3 className="text-xs font-black text-foreground uppercase tracking-widest">Class Teacher Hub</h3>
              </div>
              <div className="grid grid-cols-2 gap-2">
                {[
                  { label: 'Take Attendance', to: '/teacher/attendance', icon: <ClipboardList className="w-4 h-4" /> },
                  { label: 'Class Overview', to: '/teacher/class-overview', icon: <TrendingUp className="w-4 h-4" /> },
                  { label: 'Marks Entry', to: '/teacher/marks', icon: <Award className="w-4 h-4" /> },
                  { label: 'Homework', to: '/teacher/homework', icon: <BookOpen className="w-4 h-4" /> },
                ].map(a => (
                  <Link key={a.to} to={a.to} className="flex flex-col items-center gap-1.5 p-3 bg-background border border-border rounded-xl hover:bg-accent hover:border-primary/30 transition group text-center">
                    <span className="text-primary group-hover:scale-110 transition-transform">{a.icon}</span>
                    <span className="text-[10px] font-bold text-foreground">{a.label}</span>
                  </Link>
                ))}
              </div>
            </div>
          )}

          {/* Today's Attendance Summary */}
          {isClassTeacher && todayAttendance && todayAttendance.length > 0 && (
            <div className="bg-card border border-border rounded-2xl p-4">
              <h3 className="text-xs font-black text-foreground uppercase tracking-widest mb-3">Today's Attendance</h3>
              <div className="space-y-2">
                {[
                  { label: 'Present', count: present, color: 'bg-emerald-500' },
                  { label: 'Absent', count: absent, color: 'bg-red-500' },
                  { label: 'Late', count: late, color: 'bg-amber-500' },
                  { label: 'Half Day', count: halfDay, color: 'bg-blue-500' },
                ].map(item => (
                  <div key={item.label} className="flex items-center gap-2">
                    <div className={`w-2 h-2 rounded-full ${item.color}`} />
                    <span className="text-xs text-muted-foreground flex-1">{item.label}</span>
                    <span className="text-xs font-bold text-foreground">{item.count}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Pending Homework */}
          <div className="bg-card border border-border rounded-2xl overflow-hidden">
            <div className="flex items-center justify-between px-4 py-3 border-b border-border">
              <h3 className="text-xs font-black text-foreground uppercase tracking-widest">Upcoming Homework</h3>
              <Link to="/teacher/homework" className="text-[10px] font-bold text-primary hover:opacity-80">View all</Link>
            </div>
            <div className="divide-y divide-border">
              {pendingHomework?.length === 0 ? (
                <p className="text-[10px] text-muted-foreground text-center py-4">No pending homework</p>
              ) : (
                pendingHomework?.slice(0, 4).map((hw, i) => (
                  <div key={i} className="px-4 py-2.5">
                    <p className="text-xs font-bold text-foreground truncate">{hw.title}</p>
                    <p className="text-[10px] text-muted-foreground">{hw.Class?.name} - {hw.Subject?.name} - Due {new Date(hw.dueDate).toLocaleDateString()}</p>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const getGreeting = () => {
  const h = new Date().getHours();
  if (h < 12) return 'Morning';
  if (h < 17) return 'Afternoon';
  return 'Evening';
};

const StatCard = ({ icon, label, value, color }) => {
  const colors = {
    blue: 'bg-blue-500/10 text-blue-500 border-blue-500/20',
    emerald: 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
    amber: 'bg-amber-500/10 text-amber-500 border-amber-500/20',
    purple: 'bg-purple-500/10 text-purple-500 border-purple-500/20',
  };
  return (
    <div className="bg-card border border-border rounded-2xl p-4 flex items-center gap-3">
      <div className={`p-2.5 rounded-xl border ${colors[color]}`}>
        {React.cloneElement(icon, { className: 'w-4 h-4' })}
      </div>
      <div>
        <p className="text-lg font-black text-foreground">{value}</p>
        <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">{label}</p>
      </div>
    </div>
  );
};

const ScheduleRow = ({ slot }) => {
  const now = new Date();
  const [startH, startM] = slot.startTime.split(':').map(Number);
  const [endH, endM] = slot.endTime.split(':').map(Number);
  const isNow = now.getHours() * 60 + now.getMinutes() >= startH * 60 + startM &&
    now.getHours() * 60 + now.getMinutes() <= endH * 60 + endM;

  return (
    <div className={`flex items-center gap-4 px-5 py-3 ${isNow ? 'bg-primary/5 border-l-2 border-primary' : ''}`}>
      <div className="text-center w-16 flex-shrink-0">
        <p className={`text-xs font-black ${isNow ? 'text-primary' : 'text-foreground'}`}>{slot.startTime}</p>
        <p className="text-[10px] text-muted-foreground">{slot.endTime}</p>
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-xs font-bold text-foreground truncate">{slot.Subject?.name}</p>
        <p className="text-[10px] text-muted-foreground">{slot.Class?.name} - {slot.Section?.name}{slot.roomNo ? ` - Room ${slot.roomNo}` : ''}</p>
      </div>
      {isNow && <span className="text-[9px] font-black text-primary bg-primary/10 px-2 py-0.5 rounded-full uppercase tracking-wider animate-pulse">Live</span>}
    </div>
  );
};

const LoadingScreen = () => (
  <div className="flex items-center justify-center h-64">
    <div className="flex flex-col items-center gap-3">
      <div className="w-8 h-8 border-2 border-primary/20 border-t-primary rounded-full animate-spin" />
      <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest">Loading...</p>
    </div>
  </div>
);

export default TeacherDashboard;

